        const realStepIdx = nextStep % TOTAL_STEPS;

        tracksRef.current.forEach(track => {
          if (track.steps[realStepIdx]) {
            audioEngine.playInstrument(track.id, absoluteScheduleTime);
          }

          // Schedule freeform notes that fall in this step's window
          const windowStart = nextStepTime / loopDuration;
          const windowEnd = (nextStepTime + stepDuration) / loopDuration;

          track.freeformNotes.forEach(note => {
            // Adjust note offset for wrapping
            if (note.offset >= windowStart && note.offset < windowEnd) {
              const preciseTime = loopStartAudioTimeRef.current + (loopCount * loopDuration) + (note.offset * loopDuration);
              audioEngine.playInstrument(track.id, preciseTime);
            }
          });
        });

        lastStepScheduledRef.current = nextStep;
      }
    };

    timerRef.current = window.setInterval(scheduler, 25);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isPlaying]);

